#include<bits/stdc++.h>
using namespace std;
long long n,m,a[42];
long long cnt;
void dfs(long long k,long long sum) {
	if(sum>m)	return;
	if(k==n+1) {
		cnt++;
		return;
	}
	dfs(k+1,sum+a[k]);
	dfs(k+1,sum);
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(long long i=1; i<=n; i++)	cin>>a[i];
	dfs(1,0);
	cout<<cnt;
	return 0;
}
